   146→      title={shape.name}
   147→    >
   148→      {/* Shape Preview */}
   149→      <div className="w-16 h-16 flex items-center justify-center">
   150→        <ShapePreview shape={shape} />
   151→      </div>
   152→
   153→      {/* Shape Name */}
   154→      <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary text-center line-clamp-2">
   155→        {shape.name}
   156→      </span>
   157→    </button>
   158→  );
   159→}
   160→
   161→// Render shape preview (simplified SVG)
   162→interface ShapePreviewProps {
   163→  shape: ShapeDefinition;
   164→}
   165→
   166→function ShapePreview({ shape }: ShapePreviewProps) {
   167→  const width = 60;
   168→  const height = 60;
   169→
   170→  // Scale path to fit preview
   171→  const scaledPath = shape.pathData
   172→    ? scalePathToFit(shape.pathData, shape.defaultProps.width || 100, shape.defaultProps.height || 100, width, height)
   173→    : null;
   174→
   175→  if (shape.primitiveType === 'rectangle') {
   176→    return (
   177→      <svg width={width} height={height} viewBox={`0 0 ${width} ${height}`}>
   178→        <rect
   179→          x={5}
   180→          y={5}
   181→          width={width - 10}
   182→          height={height - 10}
   183→          fill="none"
   184→          stroke="currentColor"
   185→          strokeWidth={2}
   186→          rx={shape.defaultProps.cornerRadius ? 5 : 0}
   187→        />
   188→      </svg>
   189→    );
   190→  }
   191→
   192→  if (shape.primitiveType === 'circle') {
   193→    return (
   194→      <svg width={width} height={height} viewBox={`0 0 ${width} ${height}`}>
   195→        <circle
   196→          cx={width / 2}
   197→          cy={height / 2}
   198→          r={(width - 10) / 2}
   199→          fill="none"
   200→          stroke="currentColor"
   201→          strokeWidth={2}
   202→        />
   203→      </svg>
   204→    );
   205→  }
   206→
   207→  if (scaledPath) {
   208→    return (
   209→      <svg width={width} height={height} viewBox={`0 0 ${width} ${height}`}>
   210→        <path d={scaledPath} fill="none" stroke="currentColor" strokeWidth={2} />
   211→      </svg>
   212→    );
   213→  }
   214→
   215→  // Fallback: simple box
   216→  return (
   217→    <svg width={width} height={height} viewBox={`0 0 ${width} ${height}`}>
   218→      <rect
   219→        x={5}
   220→        y={5}
   221→        width={width - 10}
   222→        height={height - 10}
   223→        fill="none"
   224→        stroke="currentColor"
   225→        strokeWidth={2}
   226→      />
   227→    </svg>
   228→  );
   229→}
   230→
   231→// Helper: Scale SVG path to fit preview dimensions
   232→function scalePathToFit(
   233→  path: string,
   234→  originalWidth: number,
   235→  originalHeight: number,
   236→  targetWidth: number,
   237→  targetHeight: number
   238→): string {
   239→  const padding = 5;
   240→  const scaleX = (targetWidth - padding * 2) / originalWidth;
   241→  const scaleY = (targetHeight - padding * 2) / originalHeight;
   242→
   243→  // Use the smaller scale to maintain aspect ratio
   244→  const scale = Math.min(scaleX, scaleY);
   245→
   246→  // Center the shape
   247→  const offsetX = (targetWidth - originalWidth * scale) / 2;
   248→  const offsetY = (targetHeight - originalHeight * scale) / 2;
   249→
   250→  // Simple regex-based scaling (not perfect but works for basic paths)
   251→  return path
   252→    .replace(/M\s*([\d.]+)\s+([\d.]+)/g, (_match, x, y) => {
   253→      return `M ${parseFloat(x) * scale + offsetX} ${parseFloat(y) * scale + offsetY}`;
   254→    })
   255→    .replace(/L\s*([\d.]+)\s+([\d.]+)/g, (_match, x, y) => {
   256→      return `L ${parseFloat(x) * scale + offsetX} ${parseFloat(y) * scale + offsetY}`;
   257→    })
   258→    .replace(/Q\s*([\d.]+)\s+([\d.]+)\s+([\d.]+)\s+([\d.]+)/g, (_match, x1, y1, x2, y2) => {
   259→      return `Q ${parseFloat(x1) * scale + offsetX} ${parseFloat(y1) * scale + offsetY} ${parseFloat(x2) * scale + offsetX} ${parseFloat(y2) * scale + offsetY}`;
   260→    });
   261→}
   262→

